// 準備排程執行參數
const schedule = $input.item.json;

// 構建執行參數
const executionParams = {
  schedule_id: schedule.id,
  record_uuid: schedule.record_uuid,
  task_type: schedule.task_type,
  task_parameters: schedule.task_parameters,
  task_description: schedule.task_description,
  user_id: schedule.user_id,
  user_name: schedule.user_name,
  channel_id: schedule.channel_id || $env.TEAMS_DEFAULT_CHANNEL,
  handler_agent: schedule.handler_agent || 'AI Agent2',
  timeout_seconds: schedule.timeout_seconds || 300
};

// 更新狀態為 executing
const updateQuery = `EXEC sp_update_schedule_status 
  @schedule_id = ${schedule.id},
  @new_status = 'executing'`;

return [
  {
    json: {
      ...schedule,
      execution_params: executionParams,
      update_query: updateQuery
    }
  }
];

// 執行查詢工單任務
const params = $input.item.json.execution_params;

// 構建NOCTT查詢參數
const queryParams = JSON.parse(params.task_parameters || '{}');

// 根據參數生成SQL查詢
let sqlQuery = "SELECT TOP 100 * FROM NOC_TT_AI_3 WHERE 1=1";

if (queryParams.class_level) {
  sqlQuery += ` AND Class_Level = '${queryParams.class_level.replace(/[';]/g, '')}'`;
}

if (queryParams.status) {
  sqlQuery += ` AND Status = '${queryParams.status.replace(/[';]/g, '')}'`;
}

if (queryParams.date_range) {
  const startDate = new Date();
  startDate.setDate(startDate.getDate() - (queryParams.date_range.days || 7));
  sqlQuery += ` AND Created_Date >= '${startDate.toISOString().split('T')[0]}'`;
}

sqlQuery += " ORDER BY Created_Date DESC";

return [
  {
    json: {
      ...$input.item.json,
      sql_query: sqlQuery,
      target_tool: "NOCTT",
      execution_type: "query_ticket"
    }
  }
];

// 執行提醒任務
const params = $input.item.json.execution_params;

// 構建提醒訊息
const reminderMessage = `⏰ 提醒：${params.task_description}\n\n` +
  `📅 預定時間：${new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei' })}\n` +
  `👤 建立者：${params.user_name}`;

return [
  {
    json: {
      ...$input.item.json,
      reminder_message: reminderMessage,
      execution_type: "reminder"
    }
  }
];

// 處理查詢結果
const queryResult = $input.item.json;
const scheduleData = $input.item.json[0]?.json?.scheduleData || $input.item.json;

// 格式化結果
let formattedResult = "查詢完成！\\n\\n";

if (queryResult && queryResult.length > 0) {
  formattedResult += `📊 找到 ${queryResult.length} 筆記錄\\n\\n`;

  // 取前5筆顯示摘要
  const sampleCount = Math.min(5, queryResult.length);
  for (let i = 0; i < sampleCount; i++) {
    const record = queryResult[i];
    formattedResult += `${i+1}. ${record.Class_Level || 'N/A'} - ${record.Status || 'N/A'} - ${record.Created_Date || 'N/A'}\n`;
  }

  if (queryResult.length > sampleCount) {
    formattedResult += `... 還有 ${queryResult.length - sampleCount} 筆記錄\n`;
  }
} else {
  formattedResult += "📭 未找到符合條件的記錄\n";
}

return [
  {
    json: {
      ...scheduleData,
      query_result: queryResult,
      formatted_result: formattedResult,
      result_count: queryResult ? queryResult.length : 0,
      execution_status: "success"
    }
  }
];

// 合併所有執行結果
const executionResult = $input.item.json;

// 構建Teams訊息
let teamsMessage = "";

if (executionResult.execution_type === "query_ticket") {
  teamsMessage = `✅ 工單查詢完成：${executionResult.task_description}\n\n` +
    executionResult.formatted_result +
    `\n⏱️ 執行時間：${new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei' })}`;
} else if (executionResult.execution_type === "reminder") {
  teamsMessage = executionResult.reminder_message;
}

// 添加任務ID
if (executionResult.schedule_id) {
  teamsMessage += `\n📋 任務ID：${executionResult.schedule_id}`;
}

return [
  {
    json: {
      ...executionResult,
      teams_message: teamsMessage,
      final_status: "completed"
    }
  }
];

// 錯誤處理函數
const errorData = $input.item.json;

// 記錄錯誤日誌
const errorLog = {
  timestamp: new Date().toISOString(),
  schedule_id: errorData.schedule_id,
  error_type: errorData.error?.type || 'unknown',
  error_message: errorData.error?.message || '未知錯誤',
  stack_trace: errorData.error?.stack,
  execution_context: errorData
};

// 構建錯誤訊息
let errorMessage = `❌ 任務執行失敗：${errorData.task_description || '未知任務'}\n\n` +
  `⚠️ 錯誤原因：${errorData.error?.message || '未知錯誤'}\n` +
  `🔧 建議操作：請聯繫系統管理員或稍後重試\n` +
  `⏱️ 發生時間：${new Date().toLocaleString('zh-TW', { timeZone: 'Asia/Taipei' })}`;

if (errorData.schedule_id) {
  errorMessage += `\n📋 任務ID：${errorData.schedule_id}`;
}

return [
  {
    json: {
      ...errorData,
      error_log: errorLog,
      error_message_display: errorMessage,
      final_status: "failed"
    }
  }
];
